-- Widen the EntityField.ExtendedType CHECK constraint to allow 'Icon'.
--
-- This lets metadata authors explicitly declare the rendered format of a long-text
-- field (nvarchar(max), ntext, etc.). When ExtendedType is set, the form field honors
-- it directly; when it is NULL, the Angular form field falls back to lightweight,
-- client-side content auto-detection.
--
-- 'Icon' declares that a field's VALUES are icon CSS classes (e.g. Font Awesome,
-- "fa-solid fa-user") rather than ordinary text. UI surfaces (form fields, FK
-- record-link dropdowns, grids) can then render the value as a per-row icon
-- instead of a string — without any field-name guessing.
--
-- DDL only: CodeGen regenerates the EntityFieldValue list + typed unions from
-- this constraint and the extended property below.
--
-- Drop the existing constraint and re-create it with 'Icon' added (placed after
-- 'HTML', matching the alphabetical-ish ordering of the prior Markdown/HTML add).
ALTER TABLE ${flyway:defaultSchema}.EntityField DROP CONSTRAINT CK_EntityField_ExtendedType;
ALTER TABLE ${flyway:defaultSchema}.EntityField ADD CONSTRAINT CK_EntityField_ExtendedType CHECK (
    ExtendedType IN ('Code', 'Email', 'FaceTime', 'Geo', 'GeoLatitude', 'GeoLongitude', 'GeoCountry', 'GeoStateProvince', 'GeoCity', 'GeoPostalCode', 'GeoAddress', 'HTML', 'Icon', 'Markdown', 'MSTeams', 'Other', 'SIP', 'SMS', 'Skype', 'Tel', 'URL', 'WhatsApp', 'ZoomMtg')
);
GO

-- Backfill: opt existing icon-bearing fields into the new behavior. Any field
-- whose Name contains 'Icon' and has no ExtendedType set is assumed to hold an
-- icon class (e.g. Icon, IconClass, DisplayIcon, IconURL...). Only touches rows
-- where ExtendedType IS NULL, so explicit choices are preserved.
UPDATE ${flyway:defaultSchema}.EntityField
   SET ExtendedType = 'Icon'
 WHERE ExtendedType IS NULL
   AND Name LIKE '%Icon%';
GO

-- Refresh the column's documentation so CodeGen carries the new option through
-- the entity metadata (the property already exists from the baseline, so UPDATE).
EXEC sp_updateextendedproperty
    @name = N'MS_Description',
    @value = N'Defines extended behaviors for a field such as Email, Web URLs, Code, Markdown, HTML, and Icon. When set to ''Icon'', the field''s values are treated as icon CSS classes (e.g. Font Awesome) for per-row display in the UI.',
    @level0type = N'SCHEMA', @level0name = N'${flyway:defaultSchema}',
    @level1type = N'TABLE',  @level1name = N'EntityField',
    @level2type = N'COLUMN', @level2name = N'ExtendedType';
GO










































